   543→// RECRUITER - ONBOARDING DOCUMENTS VISIBILITY
   544→// ============================================
   545→
   546→// Get all onboarding documents for recruiter's company (all candidates)
   547→router.get('/recruiter/documents', authMiddleware, async (req, res) => {
   548→  try {
   549→    // Verify user is a recruiter with company_id
   550→    if (!req.user.company_id) {
   551→      return res.status(403).json({ error: 'Only recruiters can view onboarding documents' });
   552→    }
   553→
   554→    const result = await pool.query(
   555→      `SELECT
   556→        od.*,
   557→        u.name as candidate_name,
   558→        u.email as candidate_email,
   559→        oc.title as checklist_title,
   560→        oc.status as checklist_status,
   561→        oc.due_date
   562→      FROM onboarding_documents od
   563→      JOIN users u ON od.candidate_id = u.id
   564→      LEFT JOIN onboarding_checklists oc ON od.checklist_id = oc.id
   565→      WHERE od.company_id = $1 OR oc.offer_id IN (
   566→        SELECT id FROM offers WHERE company_id = $2
   567→      )
   568→      ORDER BY od.created_at DESC`,
   569→      [req.user.company_id, req.user.company_id]
   570→    );
   571→
   572→    res.json(result.rows);
   573→  } catch (err) {
