  1114→async function upsertDocument(checklistId, candidateId, companyId, docType, content, summary) {
  1115→  // Check if already exists
  1116→  const existing = await pool.query(
  1117→    'SELECT * FROM onboarding_documents WHERE checklist_id = $1 AND candidate_id = $2 AND document_type = $3',
  1118→    [checklistId, candidateId, docType]
