   603→
   604→    function getToken() {
   605→      return localStorage.getItem(TOKEN_KEY);
   606→    }
   607→
   608→    function getAuthHeaders() {
   609→      const token = getToken();
   610→      return token ? {
   611→        'Authorization': `Bearer ${token}`,
   612→        'Content-Type': 'application/json'
   613→      } : {};
   614→    }
   615→
   616→    // Initialize
   617→    document.addEventListener('DOMContentLoaded', async () => {
   618→      const token = getToken();
   619→      if (!token) {
   620→        window.location.href = '/login.html';
   621→        return;
   622→      }
   623→
   624→      // Load user info for sidebar
   625→      try {
   626→        const userRes = await fetch('/api/auth/me', { headers: { 'Authorization': `Bearer ${token}` } });
   627→        if (userRes.ok) {
   628→          const userData = await userRes.json();
   629→          document.getElementById('user-name').textContent = userData.name || 'User';
   630→          document.getElementById('user-avatar').textContent = (userData.name || 'U')[0].toUpperCase();
   631→          if (document.getElementById('dropdown-user-name')) {
   632→            document.getElementById('dropdown-user-name').textContent = userData.name || 'User';
   633→            document.getElementById('dropdown-user-email').textContent = userData.email || '';
   634→          }
   635→        }
   636→      } catch(e) { /* ignore */ }
   637→
   638→      // Setup user dropdown
   639→      const toggle = document.getElementById('user-menu-toggle');
   640→      const menu = document.getElementById('user-dropdown-menu');
   641→      if (toggle && menu) {
   642→        toggle.addEventListener('click', () => menu.classList.toggle('active'));
   643→        document.addEventListener('click', (e) => {
   644→          if (!toggle.contains(e.target) && !menu.contains(e.target)) menu.classList.remove('active');
   645→        });
   646→      }
   647→
   648→      const logoutBtn = document.getElementById('logout-btn');
   649→      if (logoutBtn) {
   650→        logoutBtn.addEventListener('click', () => {
   651→          localStorage.removeItem(TOKEN_KEY);
   652→          localStorage.removeItem('rekrutai_refresh');
   653→          window.location.href = '/login.html';
   654→        });
   655→      }
   656→
   657→      await loadWizardProgress();
   658→    });
   659→
   660→    async function loadWizardProgress() {
   661→      try {
   662→        const res = await fetch('/api/onboarding/wizard/progress', {
   663→          headers: { 'Authorization': `Bearer ${getToken()}` }
   664→        });
   665→
   666→        if (!res.ok) {
   667→          if (res.status === 401) {
   668→            window.location.href = '/login.html';
   669→            return;
   670→          }
   671→          throw new Error('Failed to load progress');
   672→        }
   673→
   674→        const data = await res.json();
   675→
   676→        document.getElementById('loadingState').style.display = 'none';
   677→
   678→        if (!data.has_onboarding) {
   679→          document.getElementById('noOnboarding').style.display = 'block';
   680→          await loadOffers();
   681→          return;
   682→        }
   683→
   684→        checklistData = data.checklist;
   685→        wizardState = data.wizard;
   686→        documentsData = data.documents || [];
   687→
   688→        // Determine current step
   689→        const stepsCompleted = wizardState.steps_completed || [];
   690→        if (wizardState.wizard_status === 'completed') {
   691→          currentStep = 5;
   692→        } else {
   693→          currentStep = wizardState.current_step || 1;
   694→        }
   695→
   696→        // Show wizard
   697→        document.getElementById('wizardContent').style.display = 'block';
   698→
   699→        // Set offer banner
   700→        document.getElementById('offerTitle').textContent =
   701→          `Welcome to ${checklistData.company_name || 'the team'}!`;
   702→        document.getElementById('offerDetail').textContent =
   703→          `${checklistData.offer_title || 'Position'} — Starting ${checklistData.start_date ? new Date(checklistData.start_date).toLocaleDateString() : 'soon'}`;
   704→
   705→        renderStep();
   706→      } catch (err) {
   707→        console.error('Error loading wizard:', err);
   708→        document.getElementById('loadingState').innerHTML =
   709→          '<p style="color: #ef4444;">Failed to load onboarding. Please refresh.</p>';
   710→      }
   711→    }
   712→
   713→    async function loadOffers() {
   714→      try {
   715→        const res = await fetch('/api/onboarding/offers/me', {
   716→          headers: { 'Authorization': `Bearer ${getToken()}` }
   717→        });
   718→        const offers = await res.json();
   719→        const pendingOffers = offers.filter(o => o.status === 'sent');
   720→
   721→        if (pendingOffers.length > 0) {
   722→          const area = document.getElementById('offersArea');
   723→          area.innerHTML = pendingOffers.map(o => `
   724→            <div style="background: var(--card-bg); border: 1px solid var(--border-color); border-radius: 12px; padding: 20px; margin-bottom: 12px; text-align: left;">
   725→              <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 12px;">
   726→                <div>
   727→                  <strong style="color: var(--text-primary);">${escapeHtml(o.title)}</strong>
   728→                  <span style="color: var(--text-muted); font-size: 13px;"> at ${escapeHtml(o.company_name)}</span>
   729→                </div>
   730→                <span class="badge badge-pending">Pending</span>
   731→              </div>
   732→              <div style="display: flex; gap: 8px;">
   733→                <button onclick="acceptOffer(${o.id})" class="btn btn-success" style="flex:1;">Accept Offer</button>
   734→                <button onclick="declineOffer(${o.id})" class="btn btn-secondary" style="flex:1;">Decline</button>
   735→              </div>
   736→            </div>
   737→          `).join('');
   738→          document.querySelector('.no-onboarding h2').textContent = 'You Have Pending Offers';
   739→          document.querySelector('.no-onboarding p').textContent = 'Accept an offer below to start your onboarding.';
   740→        }
   741→      } catch(e) {
   742→        console.error('Error loading offers:', e);
   743→      }
   744→    }
