  1226→    // ====== Signature Canvas ======
  1227→    function initSignatureCanvas() {
  1228→      const canvas = document.getElementById('signatureCanvas');
  1229→      if (!canvas) return;
  1230→
  1231→      signatureCanvas = canvas;
  1232→      signatureCtx = canvas.getContext('2d');
  1233→
  1234→      // Set canvas size
  1235→      const rect = canvas.parentElement.getBoundingClientRect();
  1236→      canvas.width = rect.width - 48;
  1237→      canvas.height = 150;
  1238→
  1239→      signatureCtx.strokeStyle = '#1a1a2e';
  1240→      signatureCtx.lineWidth = 2;
  1241→      signatureCtx.lineCap = 'round';
  1242→      signatureCtx.lineJoin = 'round';
  1243→
  1244→      canvas.addEventListener('mousedown', startDrawing);
  1245→      canvas.addEventListener('mousemove', draw);
  1246→      canvas.addEventListener('mouseup', stopDrawing);
  1247→      canvas.addEventListener('mouseleave', stopDrawing);
  1248→
  1249→      // Touch support
  1250→      canvas.addEventListener('touchstart', (e) => {
  1251→        e.preventDefault();
  1252→        const touch = e.touches[0];
  1253→        const rect = canvas.getBoundingClientRect();
  1254→        startDrawing({ offsetX: touch.clientX - rect.left, offsetY: touch.clientY - rect.top });
  1255→      });
  1256→      canvas.addEventListener('touchmove', (e) => {
  1257→        e.preventDefault();
  1258→        const touch = e.touches[0];
  1259→        const rect = canvas.getBoundingClientRect();
  1260→        draw({ offsetX: touch.clientX - rect.left, offsetY: touch.clientY - rect.top });
  1261→      });
  1262→      canvas.addEventListener('touchend', stopDrawing);
  1263→    }
  1264→
  1265→    function startDrawing(e) {
  1266→      isDrawing = true;
  1267→      signatureCtx.beginPath();
  1268→      signatureCtx.moveTo(e.offsetX, e.offsetY);
  1269→    }
  1270→
  1271→    function draw(e) {
  1272→      if (!isDrawing) return;
  1273→      signatureCtx.lineTo(e.offsetX, e.offsetY);
  1274→      signatureCtx.stroke();
  1275→      hasSigned = true;
  1276→      const btn = document.getElementById('signAllBtn');
  1277→      if (btn) btn.disabled = false;
  1278→    }
  1279→
  1280→    function stopDrawing() {
  1281→      isDrawing = false;
  1282→    }
  1283→
  1284→    function clearSignature() {
  1285→      if (!signatureCanvas || !signatureCtx) return;
  1286→      signatureCtx.clearRect(0, 0, signatureCanvas.width, signatureCanvas.height);
  1287→      hasSigned = false;
  1288→      const btn = document.getElementById('signAllBtn');
  1289→      if (btn) btn.disabled = true;
  1290→    }
  1291→
  1292→    function typeSignature() {
  1293→      const name = prompt('Type your full legal name as your signature:');
  1294→      if (!name || !name.trim()) return;
  1295→
  1296→      if (!signatureCanvas || !signatureCtx) return;
  1297→      signatureCtx.clearRect(0, 0, signatureCanvas.width, signatureCanvas.height);
  1298→      signatureCtx.font = 'italic 32px "Times New Roman", serif';
  1299→      signatureCtx.fillStyle = '#1a1a2e';
  1300→      signatureCtx.textAlign = 'center';
  1301→      signatureCtx.fillText(name.trim(), signatureCanvas.width / 2, 90);
  1302→      hasSigned = true;
  1303→      const btn = document.getElementById('signAllBtn');
  1304→      if (btn) btn.disabled = false;
  1305→    }
