  1307→    // ====== Navigation & Save ======
  1308→    function goToStep(step) {
  1309→      currentStep = step;
  1310→      renderStep();
  1311→      window.scrollTo({ top: 0, behavior: 'smooth' });
  1312→    }
  1313→
  1314→    async function saveWizardStep(step, data) {
  1315→      showSaving();
  1316→      try {
  1317→        const res = await fetch('/api/onboarding/wizard/save-step', {
  1318→          method: 'POST',
  1319→          headers: getAuthHeaders(),
  1320→          body: JSON.stringify({
  1321→            checklist_id: checklistData.id,
  1322→            step: step,
  1323→            data: data
  1324→          })
  1325→        });
  1326→
  1327→        if (!res.ok) throw new Error('Failed to save');
  1328→
  1329→        const result = await res.json();
  1330→        wizardState = result.wizard;
  1331→
  1332→        hideSaving();
  1333→
  1334→        // If step 3 just completed, generate documents
  1335→        if (step === 3) {
  1336→          await generateDocuments();
  1337→        }
  1338→
  1339→        currentStep = step + 1;
  1340→        renderStep();
  1341→        window.scrollTo({ top: 0, behavior: 'smooth' });
  1342→      } catch (err) {
  1343→        hideSaving();
  1344→        console.error('Error saving step:', err);
  1345→        alert('Failed to save. Please try again.');
  1346→      }
  1347→    }
  1348→
  1349→    async function generateDocuments() {
  1350→      try {
  1351→        const res = await fetch('/api/onboarding/wizard/generate-documents', {
  1352→          method: 'POST',
  1353→          headers: getAuthHeaders(),
  1354→          body: JSON.stringify({ checklist_id: checklistData.id })
  1355→        });
  1356→
  1357→        if (!res.ok) throw new Error('Failed to generate');
  1358→
  1359→        const result = await res.json();
  1360→        documentsData = result.documents;
  1361→      } catch (err) {
  1362→        console.error('Error generating documents:', err);
  1363→      }
  1364→    }
  1365→
  1366→    async function signAllDocuments() {
  1367→      if (!hasSigned) {
  1368→        alert('Please draw or type your signature first.');
  1369→        return;
  1370→      }
  1371→
  1372→      const signatureDataUrl = signatureCanvas ? signatureCanvas.toDataURL('image/png') : 'typed_signature';
  1373→
  1374→      showSaving();
  1375→      try {
  1376→        const res = await fetch('/api/onboarding/wizard/sign-all', {
  1377→          method: 'POST',
  1378→          headers: getAuthHeaders(),
  1379→          body: JSON.stringify({
  1380→            checklist_id: checklistData.id,
  1381→            signature_data: signatureDataUrl
  1382→          })
  1383→        });
  1384→
  1385→        if (!res.ok) throw new Error('Failed to sign');
  1386→
  1387→        const result = await res.json();
  1388→        documentsData = result.signed_documents;
  1389→
  1390→        hideSaving();
  1391→
  1392→        // Move to completion
  1393→        currentStep = 5;
  1394→        if (wizardState) wizardState.wizard_status = 'completed';
  1395→        renderStep();
  1396→        window.scrollTo({ top: 0, behavior: 'smooth' });
  1397→      } catch (err) {
  1398→        hideSaving();
  1399→        console.error('Error signing:', err);
  1400→        alert('Failed to sign documents. Please try again.');
  1401→      }
  1402→    }
  1403→
  1404→    function completeOnboarding() {
  1405→      currentStep = 5;
  1406→      renderStep();
  1407→    }
  1408→
  1409→    function showSaving() {
  1410→      document.getElementById('savingIndicator').style.display = 'block';
  1411→    }
  1412→
  1413→    function hideSaving() {
  1414→      document.getElementById('savingIndicator').style.display = 'none';
  1415→    }
  1416→
  1417→    function escapeHtml(text) {
  1418→      if (!text) return '';
  1419→      const map = { '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#039;' };
  1420→      return String(text).replace(/[&<>"']/g, m => map[m]);
  1421→    }
