   597→      return date.toLocaleDateString('en-US', { year: 'numeric', month: 'short', day: 'numeric' });
   598→    }
   599→
   600→    function escapeHtml(text) {
   601→      if (!text) return '';
   602→      const map = {
   603→        '&': '&amp;',
   604→        '<': '&lt;',
   605→        '>': '&gt;',
   606→        '"': '&quot;',
   607→        "'": '&#039;'
   608→      };
   609→      return text.replace(/[&<>"']/g, m => map[m]);
