   625→          <p><strong>SSN:</strong> ${content.ssn_last_four}</p>
   626→          <p><strong>Employer:</strong> ${escapeHtml(content.company || '')}</p>
   627→        `;
   628→      } else if (content.form_type === 'W-4') {
   629→        bodyHtml = `
   630→          <p style="font-weight: 600; text-align: center; margin-bottom: 12px;">W-4 Tax Withholding</p>
   631→          <p><strong>Name:</strong> ${escapeHtml(content.employee_name || '')}</p>
   632→          <p><strong>Address:</strong> ${escapeHtml(content.city_state_zip || '')}</p>
